    if (groupConnections['克罗塞尔大浴场'] && groupConnections['克罗塞尔大浴场'].关系度 > 3) hasConnection = true;
    if (groupConnections['神魔智学园'] && groupConnections['神魔智学园'].关系度 > 3) hasConnection = true;
}
